{
  "level": "A1–B2",
  "intro": "W tej sekcji poznasz <strong>szyk zdania w języku angielskim</strong>: od podstawowego układu <strong>S–V–O</strong> po pytania, przeczenia, pozycję przysłówków i bardziej zaawansowane formy emfazy.",
  "rules": [
    {
      "label": "Podstawowy szyk",
      "color": "emerald",
      "text": "Najczęstszy układ to <strong>subject + verb + object</strong>.",
      "example": "She reads books."
    },
    {
      "label": "Pytania",
      "color": "blue",
      "text": "W pytaniach <strong>operator albo czasownik posiłkowy</strong> staje przed podmiotem.",
      "example": "Do you like pizza? / Are you ready?"
    },
    {
      "label": "Przeczenia",
      "color": "rose",
      "text": "W przeczeniach dodajemy <strong>not</strong> po operatorze lub po <strong>be</strong>.",
      "example": "I do not like apples. / She is not here."
    }
  ]
}
